module top_module(
    input CLK,
    input RST,
    input START,
    input [15:0] DURATION,
    output reg PULSE
);reg [15:0] unused_count;

always @(posedge CLK) begin
    if (RST) begin
        unused_count <= 0;
        PULSE <= 0;
    end
    else if (START) begin
        if (unused_count < DURATION) begin
            unused_count <= unused_count + 1;
            PULSE <= 1;
        end
        else begin
            unused_count <= 0;
            PULSE <= 0;
        end
    end
    else begin
        unused_count <= 0;
        PULSE <= 0;
    end
end

endmodule
